\begin{align}
    &-\frac{\rho}{8}\|h\|^3 - \frac{10}{\rho^2}\Big\|\nabla^2 J(\theta_t)-U_t \Big \|^3 \leq \Big \langle {(\nabla^2 J(\theta_{t})-U_t)h}, {h}\Big \rangle,\label{first_CY}\\
    & -\frac{\rho}{8}\|h\|^3 -\frac{6}{5\sqrt{\rho}}\Big\| \nabla J(\theta_t) -v_t\Big\|^{3/2} 
    \leq \Big\langle {\nabla J(\theta_{t})-v_t}, {h}\Big\rangle.\label{second_CY}
 \end{align}

